/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    // 1. Create a Set of unique initial values S for O(1) lookups.
    const S = new Set(nums);

    let totalSum = 0;

    // 2. Iterate through each element in nums.
    for (const x of nums) {
        let minG = x;

        // 3. Find the minimum g in S such that g divides x.
        // Iterate through divisors up to sqrt(x).
        const sqrtX = Math.floor(Math.sqrt(x));

        for (let d = 1; d <= sqrtX; d++) {
            if (x % d === 0) {
                // Check divisor d
                if (S.has(d)) {
                    minG = Math.min(minG, d);
                }

                // Check the corresponding co-divisor x/d
                const d2 = x / d;
                if (S.has(d2)) {
                    minG = Math.min(minG, d2);
                }
            }
        }

        // 4. Add the minimum reachable value for x to the total sum.
        totalSum += minG;
    }

    return totalSum;
}

