        long long sqrtX = static_cast<long long>(std::sqrt(x));

        for (long long d = 1; d <= sqrtX; ++d) {
            if (x % d == 0) {
                // Check divisor d
                if (S.count(d)) {
                    minG = std::min(minG, d);
                }

                // Check the corresponding co-divisor x/d
                long long d2 = x / d;
                if (S.count(d2)) {
                    minG = std::min(minG, d2);
                }
