#include <unordered_set>
#include <algorithm>

long long solve(std::vector<long long> nums) {
    // 1. Create a Set of unique initial values S
    std::unordered_set<long long> S(nums.begin(), nums.end());

    long long totalSum = 0;

    // 2. Iterate through each element in nums.
    for (long long x : nums) {
        long long minG = x;

        // 3. Find the minimum g in S such that g divides x.
        // Iterate through divisors up to sqrt(x).
        long long limit = static_cast<long long>(std::sqrt(x));

        for (long long d = 1; d <= limit; d++) {
            if (x % d == 0) {
                // Check divisor d
                if (S.count(d)) {
                    minG = std::min(minG, d);
                }

                // Check the corresponding co-divisor x/d
                long long d2 = x / d;
                if (S.count(d2)) {
                    minG = std::min(minG, d2);
                }
            }
        }

        // 4. Add the minimum reachable value for x to the total sum.
        totalSum += minG;
    }

    return totalSum;
}
